outputs = {"item":"struct","index":"int","found":"bool"}
def process(list, fieldName, fieldValue):
    """Find first struct/dict in list where field matches value"""
    if not list or not isinstance(list, (list, tuple)):
        return None, -1, False
    field = str(fieldName or '')
    for i, item in enumerate(list):
        if isinstance(item, dict) and field in item:
            if item[field] == fieldValue:
                return item, i, True
    return None, -1, False
